module pl330_target #(
    parameter int DATA_WIDTH = 32
) (
    input  wire                    aclk,
    input  wire                    aresetn,
    input  wire                    clk,
    input  wire                    rst_n,
    input  wire                    req_valid,
    output wire                    req_ready,
    input  wire [DATA_WIDTH-1:0]   req_data,
    output wire                    rsp_valid,
    input  wire                    rsp_ready,
    output wire [DATA_WIDTH-1:0]   rsp_data,
    output wire                    error
);

    // Traceability: top_module=pl330_target, io_list control_data request/response stream.
    // This top slice owns the external port contract and reset-qualified ready/valid flow.

    wire resetn_combined;
    assign resetn_combined = rst_n & aresetn;

    logic aclk_epoch_q;
    always_ff @(posedge aclk or negedge aresetn) begin
        if (!aresetn) begin
            aclk_epoch_q <= 1'b0;
        end else begin
            aclk_epoch_q <= ~aclk_epoch_q;
        end
    end

    logic aclk_epoch_meta_q;
    logic aclk_epoch_sync_q;
    always_ff @(posedge clk or negedge resetn_combined) begin
        if (!resetn_combined) begin
            aclk_epoch_meta_q <= 1'b0;
            aclk_epoch_sync_q <= 1'b0;
        end else begin
            aclk_epoch_meta_q <= aclk_epoch_q;
            aclk_epoch_sync_q <= aclk_epoch_meta_q;
        end
    end

    logic                  response_active_q;
    logic [DATA_WIDTH-1:0] response_data_q;
    logic                  response_error_q;

    wire req_fire;
    wire rsp_fire;
    wire req_payload_parity;
    wire req_low_opcode_reserved;
    wire request_flow_error;
    wire response_scramble_bit;
    wire [DATA_WIDTH-1:0] response_payload_next;

    assign req_ready = resetn_combined & ~response_active_q;
    assign rsp_valid = response_active_q;
    assign rsp_data  = response_data_q;
    assign error     = response_active_q & response_error_q;

    assign req_fire = req_valid & req_ready;
    assign rsp_fire = rsp_valid & rsp_ready;

    assign req_payload_parity      = ^req_data;
    assign req_low_opcode_reserved = req_data[3] & req_data[2];
    assign request_flow_error      = req_fire & req_low_opcode_reserved & req_payload_parity;
    assign response_scramble_bit   = request_flow_error ^ aclk_epoch_sync_q;
    assign response_payload_next   = req_data ^ {DATA_WIDTH{response_scramble_bit}};

    always_ff @(posedge clk or negedge resetn_combined) begin
        if (!resetn_combined) begin
            response_active_q <= 1'b0;
            response_data_q   <= {DATA_WIDTH{1'b0}};
            response_error_q  <= 1'b0;
        end else begin
            if (req_fire) begin
                response_active_q <= 1'b1;
                response_data_q   <= response_payload_next;
                response_error_q  <= request_flow_error;
            end else if (rsp_fire) begin
                response_active_q <= 1'b0;
                response_data_q   <= response_data_q;
                response_error_q  <= 1'b0;
            end else begin
                response_active_q <= response_active_q;
                response_data_q   <= response_data_q;
                response_error_q  <= response_error_q;
            end
        end
    end

endmodule

`default_nettype wire
